import{_ as o,o as a,c as e,a0 as r}from"./chunks/framework.AQcSKqPn.js";const p=JSON.parse('{"title":"\\"暴食\\"权能 (Authority of Gluttony)","description":"","frontmatter":{"type":"concept","title":"\\"暴食\\"权能 (Authority of Gluttony)","created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","tags":["re-zero","authority","ability","gluttony"],"related":["re-zero-4th-season","subaru-natsuki","rem"],"sources":["anime/61316.md"],"date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"concepts/暴食权能-authority-of-gluttony.md","filePath":"concepts/暴食权能-authority-of-gluttony.md","lastUpdated":1784253727000}'),u={name:"concepts/暴食权能-authority-of-gluttony.md"};function i(n,t,s,l,h,d){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="暴食-权能-authority-of-gluttony" tabindex="-1">&quot;暴食&quot;权能 (Authority of Gluttony) <a class="header-anchor" href="#暴食-权能-authority-of-gluttony" aria-label="Permalink to &quot;&quot;暴食&quot;权能 (Authority of Gluttony)&quot;">​</a></h1><ul><li><strong>发布日期</strong>: 2026年07月10日 &quot;暴食&quot;权能（Authority of Gluttony）是《Re:Zero kara Hajimeru Isekai Seikatsu》系列中的一种邪恶力量，属于魔女教大罪司教的能力之一。</li></ul><h2 id="能力机制" tabindex="-1">能力机制 <a class="header-anchor" href="#能力机制" aria-label="Permalink to &quot;能力机制&quot;">​</a></h2><p>&quot;暴食&quot;权能能够吞噬他人的存在，具体表现为：</p><ul><li><strong>吞噬记忆</strong>：如库珥修的记忆被剥夺</li><li><strong>吞噬名字</strong>：如尤里乌斯的名字被剥夺</li><li><strong>吞噬意识</strong>：如雷姆被置于假死状态（suspended animation）</li></ul><p>这种能力造成的伤害不是物理性的，而是对受害者存在本身的抹除。受害者可能仍然活着，但其存在——记忆、身份、意识——被部分或完全剥夺。</p><h2 id="在第四季中的核心作用" tabindex="-1">在第四季中的核心作用 <a class="header-anchor" href="#在第四季中的核心作用" aria-label="Permalink to &quot;在第四季中的核心作用&quot;">​</a></h2><p>&quot;暴食&quot;权能是《Re:Zero kara Hajimeru Isekai Seikatsu 4th Season》的核心冲突来源。它直接导致了雷姆、库珥修和尤里乌斯的困境，并驱动了<a href="/llm-wiki/entities/菜月昴-subaru-natsuki">subaru-natsuki</a>寻找解救方法的整个旅程。与以往的战斗不同，昴面对的不是可以靠&quot;死亡回归&quot;简单重来的物理威胁，而是对同伴存在本身的抹除，这迫使他必须寻找新的解决路径。</p><h2 id="叙事意义" tabindex="-1">叙事意义 <a class="header-anchor" href="#叙事意义" aria-label="Permalink to &quot;叙事意义&quot;">​</a></h2><p>&quot;暴食&quot;权能代表了存在性剥夺的恐怖——受害者并非死亡，而是被从世界中抹去，其存在被遗忘。这种设定探讨了记忆、身份与存在之间的关系，以及当一个人的存在被剥夺时，留下的空洞如何影响生者。</p>',10)])])}const y=o(u,[["render",i]]);export{p as __pageData,y as default};
